SELECT ?player ?previousClub ?previousClubLabel
WHERE {
  ?player p:P1347 ?birminghamStatement .
  ?birminghamStatement ps:P1347 wd:Q31622;
                      pq:P379 ?transferFee;
                      pq:P580 ?birminghamStart.
  ?transferFee wikibase:quantityAmount ?feeValue;
               wikibase:quantityUnit wd:Q3366.
  FILTER(?feeValue = 200000)
  FILTER(?birminghamStart >= "1997-07-01T00:00:00Z"^^xsd:dateTime)
  FILTER(?birminghamStart <= "1998-06-30T23:59:59Z"^^xsd:dateTime)

  ?player p:P1347 ?previousStatement.
  ?previousStatement ps:P1347 ?previousClub;
                    pq:P582 ?previousEnd.
  FILTER(?previousEnd < ?birminghamStart)

  OPTIONAL { ?previousClub rdfs:label ?previousClubLabel. }
}
ORDER BY DESC(?birminghamStart)
LIMIT 1

